import '../models/arcano.dart';

final List<Arcano> allArcanos = [
  Arcano(id: 0, numero: 0, nombre: 'El Loco', nombreRomano: '0',
    leyEspiritual: 'Ley del Uno. El Loco representa la unidad primordial, el punto de partida antes de la manifestacion. Es la energia pura e indiferenciada que contiene todas las posibilidades del ser. Esta ley nos recuerda que todo en el universo esta interconectado y que cada viaje comienza desde la misma fuente. El Loco es el espiritu libre que aun no ha sido moldeado por las experiencias, la conciencia virgen que se lanza al vacio con fe absoluta.',
    leccionVida: 'El Buscador. La leccion principal es aprender a confiar en el proceso de la vida sin necesidad de tener todas las respuestas. El Loco nos invita a seguir nuestros impulsos mas autenticos, a escuchar la voz interior que nos guia hacia lo desconocido. Nos ensena que la verdadera sabiduria esta en la inocencia y la apertura a la experiencia. Cada paso es un salto de fe, y la energia vital nos impulsa a buscar sin miedo al fracaso.',
    miedoAsociado: 'Miedo a la vida y al compromiso con el propio camino.',
    arquetipo: 'El inocente, el sonador, el peregrino espiritual que emprende el viaje sin mapa. Representa el espiritu libre que confia en el universo y camina al borde del abismo con alegria. Es la parte de nosotros que anhela la libertad absoluta y se niega a ser encasillada por las normas sociales.',
    elemento: 'Aire', polaridad: 'Masculino (Activo)', valorNuclear: 0,
    desafio: 'El Loco debe enfrentar la tendencia a la imprudencia y la evasion. Su desafio es encontrar equilibrio entre la libertad y la responsabilidad, entre seguir sus impulsos y considerar las consecuencias. Debe aprender que no todo camino lleva a donde esperamos y que la confianza ciega puede llevar a la caida. Integrar la disciplina sin perder la espontaneidad es su gran prueba.',
    significadoPosicion: 'En una tirada, el Loco indica un nuevo comienzo, una aventura o un salto al vacio. Señala que es momento de soltar los miedos y lanzarse a lo desconocido con confianza. Puede advertir sobre la necesidad de actuar con fe, pero tambien de no ser ingenuo. En el amor sugiere una nueva relacion llena de posibilidades; en el trabajo, un proyecto innovador o un cambio de rumbo radical.',
    perspectivaTransgeneracional: 'El Loco revela patrones de lealtad familiar ciega, donde se repiten saltos al vacio sin conciencia generacional. En constelaciones, aparece cuando alguien carga el destino de un familiar excluido, caminando sin rumbo para mantener la lealtad al sistema. La sanacion llega al reconocer que el viaje es propio, no heredado.',
    colorAsociado: 'Dorado',
    nivel: 1,
    afirmacionSanadora: 'Confio en mi camino unico y me libero de las lealtades familiares invisibles que me desvian de mi proposito.'),
  Arcano(id: 1, numero: 1, nombre: 'El Mago', nombreRomano: 'I',
    leyEspiritual: 'Ley de Mentalismo. El universo es mental; todo lo que existe en el plano material fue primero un pensamiento. El Mago nos ensena que poseemos el poder de crear nuestra realidad a traves de nuestra mente consciente. Esta ley fundamental del hermetismo nos recuerda que somos co-creadores de nuestra existencia y que nuestros pensamientos moldean directamente nuestras circunstancias.',
    leccionVida: 'Aprender a centrar la mente en lo positivo y a dirigir la atencion con intencion. El Mago nos invita a tomar conciencia de nuestro poder creador y a utilizarlo con responsabilidad. Nos ensena que pensar en positivo atrae lo positivo, y que la claridad mental es la herramienta mas poderosa para manifestar nuestros deseos. Dominar la mente es dominar la realidad.',
    miedoAsociado: 'Miedo a lo nuevo y a asumir el poder personal.',
    arquetipo: 'El creador, el manifestador, el alquimista que transforma ideas en realidad. Representa la voluntad consciente, la habilidad de concentrar energia para lograr objetivos. Es el puente entre el mundo espiritual y el material, el que domina las herramientas de la creacion.',
    elemento: 'Fuego', polaridad: 'Masculino (Activo)', valorNuclear: 1,
    desafio: 'El Mago debe superar la tentacion de manipular o usar su poder para fines egoistas. Su desafio es desarrollar la disciplina mental necesaria para mantener el enfoque sin dispersarse. Tambien debe aprender a confiar en sus habilidades sin caer en la arrogancia. La verdadera maestria implica servir al bien mayor.',
    significadoPosicion: 'El Mago anuncia que tienes todas las herramientas necesarias para lograr tus metas. Es momento de actuar con confianza y determinacion. Señala que tus habilidades y talentos estan alineados para manifestar tus deseos. En el trabajo indica exito profesional y reconocimiento; en el amor, la capacidad de atraer a la pareja deseada.',
    perspectivaTransgeneracional: 'El Mago senala el poder de transformar patrones familiares a traves de la conciencia. Revela que los dones creativos pueden estar bloqueados por mandatos familiares de invisibilidad. Invita a reconocer que el verdadero poder personal rompe cadenas transgeneracionales.',
    colorAsociado: 'Rojo',
    nivel: 1,
    afirmacionSanadora: 'Tengo el poder de crear mi realidad y transformar los patrones heredados con mi conciencia y voluntad.'),
  Arcano(id: 2, numero: 2, nombre: 'La Papisa', nombreRomano: 'II',
    leyEspiritual: 'Ley de Grabacion. Todo pensamiento, palabra y accion queda registrado en el akasha, la memoria universal. La Papisa guarda los secretos del conocimiento oculto y nos recuerda que nada se pierde, todo queda impreso en el tejido del universo. Esta ley nos invita a ser conscientes de lo que sembramos en nuestra mente y en el mundo.',
    leccionVida: 'Comprender que los recuerdos dolorosos pueden ser transformados a traves de la comprension y el conocimiento. La Papisa nos ensena a mirar hacia adentro, a escuchar la voz de la intuicion y a confiar en el saber interior. Nos invita a estudiar los misterios de la vida y a desarrollar la paciencia para esperar el momento adecuado.',
    miedoAsociado: 'Miedo a recordar y a enfrentar la verdad interior.',
    arquetipo: 'La intuicion, el conocimiento oculto, la sacerdotisa que guarda los misterios. Representa la sabiduria interior, la capacidad de escuchar la voz silenciosa del alma. Es el arquetipo de la mujer sabia, la que sabe sin necesidad de explicar.',
    elemento: 'Agua', polaridad: 'Femenino (Pasivo)', valorNuclear: 2,
    desafio: 'La Papisa debe enfrentar el miedo a lo desconocido y a los propios abismos internos. Su desafio es confiar en la intuicion sin dejarse llevar por fantasias o ilusiones. Debe aprender a discernir entre la voz genuina de la sabiduria interior y los ecos del miedo o el deseo.',
    significadoPosicion: 'La Papisa sugiere que es momento de silencio, introspeccion y escucha interior. Las respuestas que buscas estan dentro de ti. Indica que debes confiar en tu intuicion y prestar atencion a los suenos y sincronicidades. En el amor sugiere una conexion profunda y espiritual; en el trabajo, un proyecto que requiere paciencia y estudio.',
    perspectivaTransgeneracional: 'La Papisa guarda los secretos familiares: hijos no reconocidos, abortos, relaciones ocultas que se transmiten en silencio por generaciones. Invita a sacar a la luz lo oculto, pues el silencio pesa en el alma familiar. La intuicion femenina es la llave para sanar la memoria del linaje.',
    colorAsociado: 'Azul',
    nivel: 1,
    afirmacionSanadora: 'Honro los secretos de mi familia y elijo sanar a traves de la verdad y la comprension.'),
  Arcano(id: 3, numero: 3, nombre: 'La Emperatriz', nombreRomano: 'III',
    leyEspiritual: 'Ley de Generacion. Todo en el universo tiene un principio femenino y uno masculino; la creacion surge de la union de ambos. La Emperatriz representa la fuerza generadora de la naturaleza, la abundancia y la fertilidad en todos los planos: material, emocional y espiritual.',
    leccionVida: 'Aprender a amar y cuidar todo aquello que se hace. La Emperatriz nos ensena a nutrir nuestros proyectos, relaciones y talentos con paciencia y dedicacion. Nos invita a conectarnos con la naturaleza, a fluir con los ciclos y a confiar en la abundancia del universo.',
    miedoAsociado: 'Miedo al parto, a la fertilidad y a la responsabilidad de crear.',
    arquetipo: 'La madre, la fertilidad, la naturaleza abundante. Representa el principio femenino en su aspecto creador y nutritivo. Es la diosa de la fertilidad, la que da vida y sustenta.',
    elemento: 'Tierra', polaridad: 'Femenino (Pasivo)', valorNuclear: 3,
    desafio: 'La Emperatriz debe equilibrar el dar y el recibir, evitando el agotamiento por sobreentregarse. Su desafio es nutrir sin sofocar, amar sin posesion. Debe aprender que el autocuidado es tan importante como cuidar de los demas.',
    significadoPosicion: 'La Emperatriz anuncia un periodo de abundancia, creatividad y crecimiento. Es momento de nutrir tus proyectos y relaciones. Indica fertilidad en todos los aspectos: puede señalar un embarazo, el nacimiento de una idea o la prosperidad material. En el amor sugiere una relacion armoniosa y fertil; en el trabajo, exito en emprendimientos creativos.',
    perspectivaTransgeneracional: 'La Emperatriz representa la linea materna y la capacidad de nutrir. Revela patrones de sobreproteccion, abandono materno o madres ausentes que se repiten. Invita a sanar la relacion con la madre terrenal y la madre cosmica para fluir en la abundancia del linaje femenino.',
    colorAsociado: 'Verde',
    nivel: 1,
    afirmacionSanadora: 'Recibo el amor y la nutricion del linaje materno, y florezco en mi propia abundancia.'),
  Arcano(id: 4, numero: 4, nombre: 'El Emperador', nombreRomano: 'IIII',
    leyEspiritual: 'Ley de Generacion (aspecto masculino). El Emperador canaliza la energia estructuradora del universo, la fuerza que da forma y orden al caos primigenio. Representa la autoridad divina que establece limites y crea las bases para la manifestacion.',
    leccionVida: 'Darse cuenta del resultado de las acciones y aprender a concretar y poner orden. El Emperador nos ensena la importancia de la disciplina, la estructura y la responsabilidad. Nos invita a tomar el mando de nuestra vida, a establecer bases solidas y a liderar con sabiduria.',
    miedoAsociado: 'Miedo a la autoridad y a ejercer el poder propio.',
    arquetipo: 'El padre, la autoridad, el lider que construye imperios. Representa el principio masculino en su aspecto estructurador y protector. Es la ley, el orden y la estabilidad.',
    elemento: 'Fuego', polaridad: 'Masculino (Activo)', valorNuclear: 4,
    desafio: 'El Emperador debe evitar caer en la rigidez, el autoritarismo o el control excesivo. Su desafio es ejercer la autoridad con justicia y compasion, sin volverse tirano. Debe aprender que el verdadero poder sirve a los demas.',
    significadoPosicion: 'El Emperador indica que es momento de tomar el control, establecer orden y construir estructuras solidas. Señala que la disciplina y la perseverancia llevaran al exito. En el trabajo sugiere un ascenso, liderazgo o inicio de un proyecto importante; en el amor, una relacion estable y madura.',
    perspectivaTransgeneracional: 'El Emperador representa la autoridad paterna y el orden jerarquico. Revela la rigidez o ausencia del padre, los abusos de poder heredados, la necesidad de restablecer el orden en el sistema familiar. Sanar la figura paterna permite construir bases solidas en la vida.',
    colorAsociado: 'Rojo',
    nivel: 1,
    afirmacionSanadora: 'Honro la autoridad masculina de mi linaje y construyo mi vida sobre bases de respeto y orden.'),
  Arcano(id: 5, numero: 5, nombre: 'El Papa', nombreRomano: 'V',
    leyEspiritual: 'Ley de Transferencia. Todo conocimiento, sabiduria y tradicion se transmite de maestro a discipulo, de generacion en generacion. El Papa representa la cadena de transmision del saber sagrado y la importancia de honrar las ensenanzas recibidas.',
    leccionVida: 'Reconocer el aprendizaje en cada circunstancia y abrirse a la guia de los que han recorrido el camino antes. El Papa nos ensena que la sabiduria no esta solo en los libros, sino en la experiencia vivida y compartida. Nos invita a encontrar nuestro propio maestro interior.',
    miedoAsociado: 'Miedo a los castigos y a la autoridad espiritual.',
    arquetipo: 'El maestro, la guia espiritual, el guardián de la tradicion. Representa la sabiduria que se transmite a traves de las generaciones, el puente entre lo divino y lo humano.',
    elemento: 'Tierra', polaridad: 'Masculino (Activo)', valorNuclear: 5,
    desafio: 'El Papa debe evitar el dogmatismo y la rigidez de creencias. Su desafio es honrar la tradicion sin quedar atrapado en ella, y ensenar sin imponer. Debe recordar que la verdadera sabiduria se adapta a cada tiempo y persona.',
    significadoPosicion: 'El Papa sugiere que busques guia espiritual o educacion formal. Es momento de aprender de un maestro, de estudiar o de compartir tu conocimiento con otros. Indica la necesidad de seguir una tradicion o encontrar un proposito superior. En el amor sugiere una relacion basada en valores compartidos; en el trabajo, mentoria o formacion.',
    perspectivaTransgeneracional: 'El Papa representa la transmision de creencias, valores y tradiciones familiares. Revela dogmas y mandatos religiosos o morales que se arrastran sin cuestionar. Invita a honrar la sabiduria ancestral sin quedar atrapado en creencias limitantes heredadas.',
    colorAsociado: 'Blanco',
    nivel: 1,
    afirmacionSanadora: 'Recibo la sabiduria de mis ancestros y transformo las creencias que ya no me sirven.'),
  Arcano(id: 6, numero: 6, nombre: 'El Enamorado', nombreRomano: 'VI',
    leyEspiritual: 'Ley de Afinidad. Lo similar atrae a lo similar; vibramos en la frecuencia de aquello que somos. El Enamorado nos ensena que el amor verdadero surge de la resonancia entre almas afines y que nuestras elecciones amorosas reflejan nuestro estado interior.',
    leccionVida: 'Aprender que el amor siempre une y que la vibracion genera afinidad con las experiencias y las personas. El Enamorado nos invita a tomar decisiones desde el corazon, a elegir conscientemente y a entender que el amor es la fuerza mas poderosa del universo.',
    miedoAsociado: 'Miedo al rechazo y a la vulnerabilidad emocional.',
    arquetipo: 'El amor, la eleccion, la union de opuestos. Representa la encrucijada del corazon, el momento de decidir desde el amor y no desde el miedo.',
    elemento: 'Aire', polaridad: 'Masculino (Activo)', valorNuclear: 6,
    desafio: 'El Enamorado debe aprender a discernir entre el amor genuino y la dependencia emocional. Su desafio es tomar decisiones desde la libertad interior, no desde la necesidad o el miedo a la soledad. Debe integrar la razon y el corazon.',
    significadoPosicion: 'El Enamorado senala una decision importante, especialmente en el amor. Indica que debes seguir tu corazon pero sin olvidar la razon. Puede anunciar una nueva relacion, un compromiso o la necesidad de elegir entre dos caminos. En el trabajo sugiere una decision crucial que afectara tu futuro profesional.',
    perspectivaTransgeneracional: 'El Enamorado revela patrones de eleccion de pareja heredados: repetir la historia de los padres, elegir desde la herida en vez del amor. Las lealtades familiares invisibles pueden estar saboteando las relaciones. La verdadera eleccion consciente rompe el ciclo.',
    colorAsociado: 'Rosado',
    nivel: 1,
    afirmacionSanadora: 'Elijo desde el amor consciente, liberandome de los patrones de pareja que heredo de mi sistema familiar.'),
  Arcano(id: 7, numero: 7, nombre: 'El Carro', nombreRomano: 'VII',
    leyEspiritual: 'Ley de Vibracion. Todo en el universo esta en constante movimiento y vibracion. El Carro representa el dominio de las fuerzas opuestas, la voluntad que conduce la energia hacia la victoria. Nos ensena que elevando nuestra vibracion atraemos el exito.',
    leccionVida: 'Superarse a si mismo cada dia a traves de la disciplina y la determinacion. El Carro nos invita a tomar las riendas de nuestro destino, a conducir nuestra vida con voluntad firme y a no rendirnos ante los obstaculos. La vibracion elevada lleva al exito.',
    miedoAsociado: 'Miedo a ser atacado o a perder el control.',
    arquetipo: 'El triunfador, la voluntad, el conductor del carro de la victoria. Representa la fuerza de voluntad que supera obstaculos y la capacidad de dirigir las energias opuestas hacia una meta comun.',
    elemento: 'Agua', polaridad: 'Masculino (Activo)', valorNuclear: 7,
    desafio: 'El Carro debe aprender a controlar sus impulsos contradictorios (las riendas). Su desafio es mantener el rumbo sin dejarse desviar por distracciones o emociones encontradas. Debe dominar su ego sin perder la humildad.',
    significadoPosicion: 'El Carro anuncia victoria, progreso y superacion de obstaculos. Es momento de avanzar con determinacion y confianza. Indica que tienes la fuerza de voluntad necesaria para lograr tus metas. En el trabajo sugiere exito y reconocimiento; en el amor, la superacion de desafios en la pareja.',
    perspectivaTransgeneracional: 'El Carro revela la voluntad del sistema familiar para superar la adversidad. Indica que se arrastra una fuerza de lucha heredada, pero tambien la necesidad de no repetir guerras que no son propias. El exito personal requiere desidentificarse de los conflictos familiares.',
    colorAsociado: 'Amarillo',
    nivel: 1,
    afirmacionSanadora: 'Conduzco mi vida con voluntad consciente, honrando la fuerza de mis ancestros sin cargar sus batallas.'),
  Arcano(id: 8, numero: 8, nombre: 'La Justicia', nombreRomano: 'VIII',
    leyEspiritual: 'Ley de Causa y Efecto. Toda accion genera una reaccion equivalente; cada semilla que sembramos, cosechamos. La Justicia nos recuerda que el universo opera con perfecto equilibrio y que cada acto tiene consecuencias que debemos asumir.',
    leccionVida: 'Comprender la pedagogia del error como proceso de aprendizaje. La Justicia nos ensena a evitar la culpa y la venganza, y a confiar en que la balanza cosmica siempre se equilibra. Nos invita a ser responsables de nuestras acciones y a actuar con integridad.',
    miedoAsociado: 'Miedo a ser enganado o a la injusticia.',
    arquetipo: 'El equilibrio, la verdad, la ley divina que equilibra todas las cosas. Representa la objetividad, la justicia imparcial y la necesidad de tomar decisiones con rectitud.',
    elemento: 'Aire', polaridad: 'Femenino (Pasivo)', valorNuclear: 8,
    desafio: 'La Justicia debe enfrentar la tendencia a juzgar severamente a los demas o a si mismo. Su desafio es aplicar la ley con compasion, entendiendo que cada alma esta en su propio proceso de aprendizaje.',
    significadoPosicion: 'La Justicia indica que recibiras lo que mereces, sean consecuencias de acciones pasadas o el resultado de tu esfuerzo. Senala la importancia de la honestidad y la responsabilidad. En el ambito legal sugiere un fallo favorable si has actuado con rectitud. En el amor, relaciones basadas en la equidad.',
    perspectivaTransgeneracional: 'La Justicia revela deudas karmicas familiares: injusticias, violaciones, abusos que claman reparacion. Invita a restablecer el equilibrio en el sistema reconociendo lo que ocurrio sin culpa ni venganza. La verdadera justicia transgeneracional es la reconciliacion.',
    colorAsociado: 'Azul',
    nivel: 2,
    afirmacionSanadora: 'Restablezco el equilibrio en mi linaje a traves de la verdad, la responsabilidad y la compasion.'),
  Arcano(id: 9, numero: 9, nombre: 'El Ermitano', nombreRomano: 'VIIII',
    leyEspiritual: 'Ley del Hermetismo. El silencio guarda la sabiduria; el conocimiento profundo se revela en la soledad y la introspeccion. El Ermitano nos ensena que las grandes verdades se encuentran en el recogimiento interior, no en el ruido exterior.',
    leccionVida: 'Prudencia, paciencia y saber cuando hablar y cuando callar. El Ermitano nos invita a aprender de los errores del pasado, a buscar la sabiduria en la soledad y a iluminar nuestro propio camino antes de querer guiar a otros.',
    miedoAsociado: 'Miedo a la soledad y al aislamiento.',
    arquetipo: 'El sabio, la introspeccion, el buscador de la verdad interior. Representa la iluminacion que surge del silencio y la soledad creativa.',
    elemento: 'Tierra', polaridad: 'Masculino (Activo)', valorNuclear: 9,
    desafio: 'El Ermitano debe evitar el aislamiento excesivo y la desconexion del mundo. Su desafio es encontrar el equilibrio entre la soledad necesaria para la reflexion y la participacion en la vida social. Debe compartir su sabiduria sin imponerse.',
    significadoPosicion: 'El Ermitano sugiere que es momento de retirarse, reflexionar y buscar respuestas en tu interior. Indica un periodo de soledad necesario para encontrar tu verdad. En el trabajo puede senalar la necesidad de concentrarte en un proyecto; en el amor, un tiempo de reflexion antes de tomar decisiones.',
    perspectivaTransgeneracional: 'El Ermitano representa la sabiduria que se alcanza cuando se rompe el aislamiento emocional heredado. Revela patrones de soledad que vienen de generaciones anteriores: excluidos, diferentes, los que no encajan. Invita a encontrar la luz interior que ilumina a todo el sistema.',
    colorAsociado: 'Morado',
    nivel: 2,
    afirmacionSanadora: 'Encuentro la sabiduria en mi interior y comparto mi luz con mi sistema familiar.'),
  Arcano(id: 10, numero: 10, nombre: 'La Rueda de la Fortuna', nombreRomano: 'X',
    leyEspiritual: 'Ley de los Ciclos o del Eterno Retorno. Todo fluye y refluye; la vida es una danza constante de ascensos y descensos. La Rueda nos recuerda que el cambio es la unica constante y que cada ciclo trae nuevas oportunidades de crecimiento.',
    leccionVida: 'Aprender la impasibilidad ante los cambios, distinguiendo entre eventos externos y estados internos. La Rueda nos ensena a fluir con los ciclos de la vida, a aceptar tanto las subidas como las bajadas con ecuanimidad.',
    miedoAsociado: 'Miedo a la pobreza y a la incertidumbre del destino.',
    arquetipo: 'El destino, el cambio ciclico, la diosa fortuna que gira su rueda incesantemente. Representa la naturaleza cambiante de la vida y la oportunidad que trae cada nuevo ciclo.',
    elemento: 'Fuego', polaridad: 'Masculino (Activo)', valorNuclear: 1,
    desafio: 'La Rueda de la Fortuna debe ensenarnos a no aferrarnos a las situaciones favorables ni a desesperarnos en las desfavorables. El desafio es mantener la ecuanimidad ante los giros del destino.',
    significadoPosicion: 'La Rueda de la Fortuna anuncia un cambio inevitable. Puede ser positivo o negativo segun las cartas circundantes, pero siempre trae crecimiento. Indica que el destino esta actuando y que debes fluir con los cambios. En el trabajo sugiere cambios importantes; en el amor, un giro inesperado en la relacion.',
    perspectivaTransgeneracional: 'La Rueda revela los ciclos que se repiten en el sistema familiar: fechas aniversario, patrones que vuelven generacion tras generacion hasta ser aprendidos. Invita a reconocer el momento de cambiar el destino familiar, de detener la rueda del karma colectivo.',
    colorAsociado: 'Naranja',
    nivel: 2,
    afirmacionSanadora: 'Acepto los ciclos de la vida y elijo cambiar los patrones que mi familia repite sin conciencia.'),
  Arcano(id: 11, numero: 11, nombre: 'La Fuerza', nombreRomano: 'XI',
    leyEspiritual: 'Ley de Absorcion. El ser puede absorber y transmutar las energias del entorno. La Fuerza nos ensena que la verdadera fortaleza no esta en la agresion sino en la resistencia serena, en la capacidad de mantener la calma ante la adversidad.',
    leccionVida: 'Fortaleza de espiritu y mantener alto el nivel de energia vital. La Fuerza nos invita a domar nuestras pasiones y miedos con amor y comprension, no con represion. Nos ensena que el verdadero poder esta en la suavidad.',
    miedoAsociado: 'Miedo a no tener el control de las propias emociones.',
    arquetipo: 'La fortaleza interior, el dominio de las pasiones, la mujer que doma al leon con amor. Representa la fuerza que surge de la conexion con el corazon.',
    elemento: 'Agua', polaridad: 'Femenino (Pasivo)', valorNuclear: 2,
    desafio: 'La Fuerza debe enfrentar los propios demonios internos con compasion, no con violencia. Su desafio es reconocer que la debilidad aparente puede ser fortaleza verdadera, y que rendirse no es fracaso.',
    significadoPosicion: 'La Fuerza indica que tienes la fortaleza interior necesaria para superar cualquier obstaculo. Confia en tu corazon y en tu capacidad de resistir con paciencia. En el amor sugiere una relacion que requiere paciencia y comprension; en el trabajo, perseverancia para lograr tus metas.',
    perspectivaTransgeneracional: 'La Fuerza revela la resiliencia del linaje, la capacidad de la familia para superar tragedias. Pero tambien advierte la tentacion de cargar el dolor de los ancestros. La verdadera fuerza es domar las pasiones heredadas con amor, no con represion.',
    colorAsociado: 'Rojo',
    nivel: 2,
    afirmacionSanadora: 'Domino mis pasiones heredadas con amor y convierto la fuerza de mis ancestros en compasion.'),
  Arcano(id: 12, numero: 12, nombre: 'El Colgado', nombreRomano: 'XII',
    leyEspiritual: 'Ley del Pendulo o del Ritmo. Todo oscila de un extremo a otro; la vida es una alternancia constante. El Colgado nos ensena que a veces es necesario detenerse, invertir la perspectiva y aceptar la suspension del movimiento.',
    leccionVida: 'Aprender a renunciar al libre albedrio y permitir que el alma decida. El Colgado nos invita a soltar el control, a aceptar la espera y a confiar en que la pausa tiene un proposito. Nos ensena que dar y recibir son la misma cosa.',
    miedoAsociado: 'Miedo a la enfermedad y a la perdida de movilidad.',
    arquetipo: 'El sacrificio, la rendicion, el que se entrega a una causa superior. Representa la capacidad de ver el mundo desde una perspectiva diferente, de encontrar la luz en la oscuridad.',
    elemento: 'Agua', polaridad: 'Masculino (Activo)', valorNuclear: 3,
    desafio: 'El Colgado debe aprender que la rendicion no es debilidad sino sabiduria. Su desafio es soltar el control sin caer en la resignacion pasiva, y encontrar el proposito en la pausa forzada.',
    significadoPosicion: 'El Colgado sugiere que es momento de detenerte, soltar el control y mirar la situacion desde otra perspectiva. Indica que la pausa es necesaria para tu crecimiento. En el amor puede senalar una relacion en pausa o la necesidad de sacrificio; en el trabajo, un proyecto detenido que requiere paciencia.',
    perspectivaTransgeneracional: 'El Colgado revela sacrificios familiares inconscientes: alguien que queda detenido para mantener el equilibrio del sistema. Invita a preguntarse: por quien me detengo? A quien estoy siendo leal con mi estancamiento? La pausa forzada tiene un proposito.',
    colorAsociado: 'Morado',
    nivel: 2,
    afirmacionSanadora: 'Me libero del sacrificio innecesario y confio en que soltar es sanar el sistema familiar.'),
  Arcano(id: 13, numero: 13, nombre: 'La Muerte', nombreRomano: 'XIII',
    leyEspiritual: 'Ley de Transformacion. Todo puede cambiar de estado; la muerte no es el final sino una transformacion profunda. Este arcano nos ensena que la unica constante es el cambio y que cada final es el principio de algo nuevo.',
    leccionVida: 'Desapego y comprension de que todo es temporal. No se es dueno de nada ni de nadie. Este arcano nos invita a soltar lo que ya no nos sirve, a dejar morir viejas estructuras para que pueda nacer lo nuevo.',
    miedoAsociado: 'Miedo a la muerte y a los cambios radicales.',
    arquetipo: 'La transformacion, la muerte y el renacimiento, el segador que abre paso a lo nuevo. Representa el poder transformador que disuelve lo viejo para dar espacio a lo fresco.',
    elemento: 'Agua', polaridad: 'Femenino (Pasivo)', valorNuclear: 4,
    desafio: 'Este arcano nos desafia a soltar el apego a lo conocido y a confiar en el proceso de transformacion. Debemos aprender que resistirse al cambio solo prolonga el sufrimiento.',
    significadoPosicion: 'Este arcano anuncia un final necesario para que algo nuevo pueda nacer. No debes temerle; la transformacion es parte natural de la vida. Indica que debes soltar relaciones, trabajos o patrones que ya cumplieron su ciclo. En el amor, un final que abre paso a algo mejor.',
    perspectivaTransgeneracional: 'Este arcano revela las muertes no elaboradas del sistema: abortos, fallecidos no llorados, relaciones no despedidas. Invita a dar lugar a los que se fueron, a honrar su memoria para que el sistema pueda transformarse. La muerte no elaborada paraliza la evolucion familiar.',
    colorAsociado: 'Negro',
    nivel: 2,
    afirmacionSanadora: 'Honro a los que se fueron antes de mi, y permito que el amor transforme la muerte en renacimiento.'),
  Arcano(id: 14, numero: 14, nombre: 'La Templanza', nombreRomano: 'XIIII',
    leyEspiritual: 'Ley de la Polaridad. Todo tiene su polo opuesto; los opuestos son complementarios, no contradictorios. La Templanza nos ensena a encontrar el punto medio, a integrar los extremos y a fluir con equilibrio.',
    leccionVida: 'Adaptabilidad y tolerancia. Comprender ambos polos nos hace tolerantes y nos permite encontrar la armonia en la diversidad. La Templanza nos invita a la paciencia, a la moderacion y a la integracion de los opuestos dentro de nosotros.',
    miedoAsociado: 'Miedo a ser acusado o juzgado por los extremos.',
    arquetipo: 'El equilibrio, la armonia, la alquimia de la integracion. Representa la capacidad de mezclar y combinar elementos opuestos para crear algo nuevo y armonioso.',
    elemento: 'Fuego', polaridad: 'Femenino (Pasivo)', valorNuclear: 5,
    desafio: 'La Templanza debe evitar la mediocridad que a veces se esconde tras la busqueda de equilibrio. Su desafio es encontrar la armonia sin perder la pasion, integrar sin diluir.',
    significadoPosicion: 'La Templanza indica que es momento de encontrar equilibrio y moderacion. La paciencia y la perspectiva te ayudaran a resolver conflictos. Sugiere que debes integrar los opuestos dentro de ti. En el amor, una relacion armoniosa basada en el respeto mutuo; en el trabajo, colaboracion y equilibrio.',
    perspectivaTransgeneracional: 'La Templanza revela la necesidad de integrar los opuestos en el sistema: las ramas enfrentadas, las historias contradictorias, las dualidades del linaje. Invita a encontrar el punto medio entre las polaridades familiares, honrando ambas caras de la historia.',
    colorAsociado: 'Verde',
    nivel: 2,
    afirmacionSanadora: 'Integro los opuestos de mi linaje y encuentro armonia en la diversidad de mi historia familiar.'),
  Arcano(id: 15, numero: 15, nombre: 'El Diablo', nombreRomano: 'XV',
    leyEspiritual: 'Ley de Metamorfosis o Multiplicacion. La energia puede transformarse y multiplicarse, para bien o para mal. El Diablo representa el poder de la materia y las ataduras que nosotros mismos creamos con nuestros miedos y deseos.',
    leccionVida: 'Sustituir el concepto de bueno o malo por el de necesario. El Diablo nos invita a enfrentar nuestras sombras, a reconocer nuestras adicciones y ataduras, y a asumir la responsabilidad de nuestra propia liberacion.',
    miedoAsociado: 'Miedo a estar encerrado o atrapado en situaciones toxicas.',
    arquetipo: 'La sombra, las ataduras, el señor del mundo material. Representa las tentaciones, los apegos y las creencias limitantes que nos mantienen esclavos.',
    elemento: 'Tierra', polaridad: 'Masculino (Activo)', valorNuclear: 6,
    desafio: 'El Diablo nos desafia a reconocer nuestras propias cadenas y a entender que nadie nos tiene atrapados sino nosotros mismos. Debemos enfrentar nuestras sombras con conciencia y asumir la responsabilidad de nuestra liberacion.',
    significadoPosicion: 'El Diablo advierte sobre adicciones, apegos poco saludables o situaciones toxicas. Te invita a examinar que te esta esclavizando: miedos, deseos materiales o relaciones destructivas. En el amor senala una relacion de codependencia o pasion destructiva; en el trabajo, la esclavitud al dinero o al poder.',
    perspectivaTransgeneracional: 'El Diablo revela las ataduras mas profundas del sistema: adicciones hereditarias, secretos de abuso, lealtades toxicas que atan al sufrimiento. Invita a mirar de frente las sombras familiares, a reconocer que solo la conciencia libera del karma familiar.',
    colorAsociado: 'Marron',
    nivel: 3,
    afirmacionSanadora: 'Reconozco las cadenas de mi linaje y elijo la conciencia como herramienta de liberacion.'),
  Arcano(id: 16, numero: 16, nombre: 'La Torre', nombreRomano: 'XVI',
    leyEspiritual: 'Ley de Contraccion. A veces el universo debe derribar lo que ya no sirve para poder construir algo nuevo. La Torre representa la crisis necesaria, el colapso de las estructuras falsas sobre las que hemos construido nuestra vida.',
    leccionVida: 'Ver la crisis como oportunidad de cambio profundo. La Torre nos ensena a aceptar que algunas etapas deben terminar abruptamente para que podamos reconstruir sobre bases mas autenticas.',
    miedoAsociado: 'Miedo a las tormentas, a los derrumbes y a las crisis repentinas.',
    arquetipo: 'La crisis, la revelacion, el colapso de las ilusiones. Representa la verdad que irrumpe violentamente para derribar las falsas seguridades.',
    elemento: 'Fuego', polaridad: 'Femenino (Pasivo)', valorNuclear: 7,
    desafio: 'La Torre nos desafia a mantener la fe cuando todo se derrumba. Debemos aprender a no aferrarnos a estructuras que ya no son solidas y a confiar en que despues de la tormenta llega la calma.',
    significadoPosicion: 'La Torre anuncia un cambio repentino y a veces traumatico, pero necesario. Una situacion que creias estable se derrumba para revelar la verdad. Indica que las falsas ilusiones deben caer. En el amor, una ruptura repentina o una revelacion impactante; en el trabajo, una crisis que abre nuevas oportunidades.',
    perspectivaTransgeneracional: 'La Torre revela las crisis necesarias que sacuden al sistema para derribar estructuras falsas: quiebras, divorcios, escandalos, perdidas. Lo que parece destruccion es la verdad irrumpiendo para liberar a las siguientes generaciones de las mentiras familiares.',
    colorAsociado: 'Rojo',
    nivel: 3,
    afirmacionSanadora: 'Acepto las crisis como purificacion del linaje, y confio en que la verdad reconstruye todo.'),
  Arcano(id: 17, numero: 17, nombre: 'La Estrella', nombreRomano: 'XVII',
    leyEspiritual: 'Ley de Armonia. El universo es un cosmos ordenado y armonioso. La Estrella nos conecta con la belleza y la perfeccion del plan divino, recordandonos que todo tiene un proposito y un lugar.',
    leccionVida: 'Aprender a agradecer todo lo que la vida da, descubriendo el secreto de la felicidad en la gratitud. La Estrella nos invita a confiar en el futuro, a mantener la esperanza y a conectarnos con nuestra inspiracion mas elevada.',
    miedoAsociado: 'Miedo a las perdidas y a la falta de direccion.',
    arquetipo: 'La esperanza, la sanacion, la estrella que guia en la oscuridad. Representa la renovacion espiritual, la inspiracion divina y la conexion con el proposito superior.',
    elemento: 'Aire', polaridad: 'Femenino (Pasivo)', valorNuclear: 8,
    desafio: 'La Estrella debe mantener la fe incluso cuando las circunstancias parecen adversas. Su desafio es no perder la esperanza y recordar que la luz siempre brilla detras de las nubes.',
    significadoPosicion: 'La Estrella es una carta de esperanza, inspiracion y renovacion. Indica que un periodo de dificultad esta llegando a su fin y que tiempos mejores se aproximan. Sugiere que debes confiar en el universo y seguir tu inspiracion. En el amor, sanacion y conexion espiritual; en el trabajo, inspiracion creativa.',
    perspectivaTransgeneracional: 'La Estrella es la luz de esperanza que guia al sistema hacia la sanacion. Revela que despues de la tormenta generacional, la inspiracion divina llega para renovar el linaje. Invita a confiar en el futuro, a sanar las heridas con gratitud y a abrir el corazon a la guia espiritual.',
    colorAsociado: 'Dorado',
    nivel: 3,
    afirmacionSanadora: 'Confio en que la luz divina guia mi linaje hacia la renovacion y la paz.'),
  Arcano(id: 18, numero: 18, nombre: 'La Luna', nombreRomano: 'XVIII',
    leyEspiritual: 'Ley de Asimilacion. La Luna regula los ciclos naturales y las mareas emocionales. Nos recuerda que existen fuerzas sutiles que influyen en nuestra psique y que debemos aprender a navegar las aguas del subconsciente.',
    leccionVida: 'Aprender a liberarse de las influencias geneticas y ancestrales, especialmente de la linea materna de la familia. La Luna nos invita a explorar nuestro mundo interior, a enfrentar nuestros miedos y a confiar en nuestra intuicion.',
    miedoAsociado: 'Miedo a la noche, a la oscuridad y a lo desconocido.',
    arquetipo: 'La ilusion, el subconsciente, los suenos y las pesadillas. Representa el mundo de las sombras, las ilusiones y los miedos que habitan en las profundidades de la psique.',
    elemento: 'Agua', polaridad: 'Femenino (Pasivo)', valorNuclear: 9,
    desafio: 'La Luna nos desafia a caminar en la oscuridad sin miedo, a confiar en nuestra intuicion cuando no hay claridad racional. Debemos aprender a distinguir entre la realidad y la ilusion, entre el miedo y la intuicion genuina.',
    significadoPosicion: 'La Luna indica que hay aspectos ocultos o ilusiones que debes examinar. No todo es lo que parece; confia en tu intuicion pero no te dejes llevar por el miedo. Puede senalar ansiedad, confusion o la necesidad de explorar tu subconsciente. En el amor, incertidumbre o secretos; en el trabajo, situaciones poco claras.',
    perspectivaTransgeneracional: 'La Luna esta directamente vinculada a la linea materna, la memoria genetica femenina y los patrones ancestrales de la madre. Revela influencias de la madre cosmica sobre la psique, las ataduras geneticas que deben soltarse. Sanar la relacion con la madre terrenal y cosmica es clave para la liberacion.',
    colorAsociado: 'Plateado',
    nivel: 3,
    afirmacionSanadora: 'Me libero de las influencias geneticas maternas que no me corresponden y camino hacia mi propia luz.'),
  Arcano(id: 19, numero: 19, nombre: 'El Sol', nombreRomano: 'XVIIII',
    leyEspiritual: 'Ley de Union Fraternal. Todos somos uno; la separacion es una ilusion. El Sol representa la luz de la conciencia que disipa las tinieblas y nos recuerda que en el fondo todos estamos conectados por el mismo amor universal.',
    leccionVida: 'Conectar con el nino interior ayuda a sanar heridas emocionales, especialmente de la linea paterna de la familia. El Sol nos invita a la alegria, a la celebracion de la vida y a reconocer nuestra propia luz interior.',
    miedoAsociado: 'Miedo a las traiciones y a la falta de reconocimiento.',
    arquetipo: 'La alegria, la realizacion, el exito radiante. Representa la iluminacion, la vitalidad y la expresion plena del ser.',
    elemento: 'Fuego', polaridad: 'Masculino (Activo)', valorNuclear: 1,
    desafio: 'El Sol nos desafia a brillar sin miedo, a compartir nuestra luz con el mundo sin temor a deslumbrar. Debemos superar la falsa modestia y reconocer nuestro propio valor.',
    significadoPosicion: 'El Sol es una de las cartas mas positivas del tarot. Anuncia exito, alegria, realizacion y vitalidad. Indica que los tiempos oscuros han pasado y que la luz brilla sobre ti. En el amor, felicidad y armonia; en el trabajo, exito y reconocimiento.',
    perspectivaTransgeneracional: 'El Sol esta vinculado a la linea paterna y al nino interior. Revela la necesidad de sanar las heridas del padre, los rencores hacia la figura paterna. Conectar con el nino interior sano permite restaurar la alegria en el linaje. El padre cosmico sostiene y protege.',
    colorAsociado: 'Dorado',
    nivel: 3,
    afirmacionSanadora: 'Sano las heridas de mi linea paterna, conecto con mi nino interior y permito que la alegria brille en mi linaje.'),
  Arcano(id: 20, numero: 20, nombre: 'El Juicio', nombreRomano: 'XX',
    leyEspiritual: 'Ley de Correspondencia. Como es arriba es abajo; como es adentro es afuera. El Juicio nos llama a despertar, a evaluar nuestra vida y a responder al llamado superior de nuestra alma.',
    leccionVida: 'Cambiar internamente para vibrar con otras circunstancias. Al cambiar el estado interior cambia la correspondencia externa. El Juicio nos invita a un renacimiento consciente, a dejar atras el pasado y a responder al llamado de nuestro destino.',
    miedoAsociado: 'Miedo a los espiritus, al juicio divino y al despertar.',
    arquetipo: 'El renacimiento, el despertar, la llamada interior que nos invita a una nueva vida. Representa el juicio final que no es castigo sino oportunidad de redencion.',
    elemento: 'Fuego', polaridad: 'Masculino (Activo)', valorNuclear: 2,
    desafio: 'El Juicio nos desafia a escuchar el llamado interior y a tener el valor de responder. Debemos superar el miedo al cambio radical y confiar en que el renacimiento es necesario.',
    significadoPosicion: 'El Juicio indica que es momento de despertar, de reevaluar tu vida y de responder a un llamado interior. Senala un renacimiento o una segunda oportunidad. El pasado queda atras y un nuevo ciclo comienza. En el amor, una segunda oportunidad o un despertar en la relacion; en el trabajo, un nuevo proposito profesional.',
    perspectivaTransgeneracional: 'El Juicio llama al despertar del sistema familiar, a responder al llamado del alma que trasciende el linaje. Invita a soltar las viejas identidades familiares para renacer a una nueva conciencia. El cambio interior de un miembro transforma a todo el sistema.',
    colorAsociado: 'Blanco',
    nivel: 3,
    afirmacionSanadora: 'Respondo al llamado de mi alma, liberando las viejas identidades familiares para renacer a mi verdadero ser.'),
  Arcano(id: 21, numero: 21, nombre: 'El Mundo', nombreRomano: 'XXI',
    leyEspiritual: 'Ley de Fusion. La separacion es una ilusion; en el fondo, todo es uno. El Mundo representa la culminacion del viaje, la integracion de todas las experiencias y la realizacion de la unidad con el Todo.',
    leccionVida: 'Aprender a sentirse completo y realizado, unido al Todo. El Mundo nos ensena que el verdadero proposito del viaje espiritual es reconocer nuestra unidad con el universo y celebrar la totalidad de nuestro ser.',
    miedoAsociado: 'Miedo al entorno y a perder la individualidad en la totalidad.',
    arquetipo: 'La completitud, la realizacion, la culminacion del viaje heroico. Representa la integracion final, la totalidad alcanzada despues de recorrer el camino de los arcanos.',
    elemento: 'Tierra', polaridad: 'Femenino (Pasivo)', valorNuclear: 3,
    desafio: 'El Mundo nos desafia a integrar todas las partes de nosotros mismos y a celebrar nuestra totalidad. Debemos aprender que la realizacion no es un destino sino un estado del ser.',
    significadoPosicion: 'El Mundo es la carta de la culminacion y el exito. Indica que has completado un ciclo importante y que has alcanzado una meta significativa. Es momento de celebrar tus logros y reconocer tu crecimiento. En el amor, una union plena y armoniosa; en el trabajo, la culminacion exitosa de un proyecto importante.',
    perspectivaTransgeneracional: 'El Mundo representa la culminacion del trabajo transgeneracional: el ciclo de repeticion se completa, las heridas ancestrales sanan. Invita a celebrar la totalidad del ser, integrando todas las ramas del arbol familiar. La mision del linaje se cumple en la unidad.',
    colorAsociado: 'Dorado',
    nivel: 3,
    afirmacionSanadora: 'Completo el ciclo de mi linaje, integro todas mis partes y celebro la unidad del ser.'),
];

Arcano? getArcanoByNumero(int numero) {
  for (var a in allArcanos) { if (a.numero == numero) return a; }
  return null;
}
